const lead = $('Set: Normalize Lead').item.json;
const tz = "America/New_York";
const startHour = 9;
const endHour = 17;
const duration = 30;

// Next business-hours slot (deterministic): roll forward to a weekday within hours.
let dt = DateTime.now().setZone(tz).plus({ hours: 1 }).startOf('hour');
function isBiz(d) { return d.weekday <= 5 && d.hour >= startHour && d.hour < endHour; }
let guard = 0;
while (!isBiz(dt) && guard < 400) {
  if (dt.weekday > 5) {
    dt = dt.plus({ days: 1 }).set({ hour: startHour, minute: 0, second: 0, millisecond: 0 });
  } else if (dt.hour < startHour) {
    dt = dt.set({ hour: startHour, minute: 0, second: 0, millisecond: 0 });
  } else {
    dt = dt.plus({ days: 1 }).set({ hour: startHour, minute: 0, second: 0, millisecond: 0 });
  }
  guard++;
}

const startISO = dt.toISO();
const endISO = dt.plus({ minutes: duration }).toISO();
const human = dt.toFormat("cccc, LLL d 'at' h:mm a");

// system_prompt is stored as a literal on the Set: AI Config node; inject the
// computed slot now (kept out of build-time substitution on purpose).
const tmpl = $('Set: AI Config').item.json.system_prompt;
const system = tmpl.split('{{CONSULT_SLOT}}').join(human);

const userMessage =
  "New lead submitted:\n" +
  "Name: " + (lead.name || "(none)") + "\n" +
  "Phone: " + (lead.phone || "(none)") + "\n" +
  "Email: " + (lead.email || "(none)") + "\n" +
  "Case description: " + (lead.case_description || "(none)");

return [{ json: { startISO, endISO, human, system, userMessage } }];

let raw = "";
try { raw = $json.content[0].text || ""; } catch (e) { raw = ""; }

let parsed = null;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  const m = raw.match(/\{[\s\S]*\}/);
  if (m) { try { parsed = JSON.parse(m[0]); } catch (e2) { parsed = null; } }
}

if (!parsed || typeof parsed.qualified === "undefined") {
  parsed = {
    qualified: false,
    reason: "AI response was unparseable; defaulted to follow-up.",
    missing_info: ["incident details"],
    sms_reply: "Thanks for reaching out! Could you share a few details about what happened and any injuries, so we can help?"
  };
}

return [{ json: {
  qualified: parsed.qualified === true,
  reason: String(parsed.reason || ""),
  missing_info: Array.isArray(parsed.missing_info) ? parsed.missing_info : [],
  sms_reply: String(parsed.sms_reply || "Thanks for reaching out — a team member will follow up shortly.")
} }];
